// LabeledServerRecord Control-plane view of a server: the tenant-agnostic “fast_gateway.ServerRecord“ plus this
// product's ABAC “labels“ (#884 Phase D). The labels live only in the control-plane “mcp_servers“
// table, so the reusable gateway library/model stays label-free; this subclass surfaces them on the
// admin read API without changing the library contract.
type LabeledServerRecord struct {
	// Allow Glob patterns of tool names to expose (empty = all).
	Allow *[]string `json:"allow,omitempty"`

	// Auth Upstream authentication scheme used when connecting to a registered server.
	//
	// ``oauth`` is the interactive browser authorization-code flow (Mode B only);
	// ``oauth_client_credentials`` is the headless machine-to-machine grant. Static
	// token / API-key auth needs no scheme: put a ``${env:}``/``${file:}`` secret
	// reference in ``static_headers`` and it resolves at connect time.
	Auth *ServerAuth `json:"auth,omitempty"`

	// Deny Glob patterns of tool names to hide (wins over allow).
	Deny    *[]string          `json:"deny,omitempty"`
	Enabled *bool              `json:"enabled,omitempty"`
	Id      string             `json:"id"`
	Labels  *map[string]string `json:"labels,omitempty"`

	// Name Unique name; also used as the mount namespace/prefix. Letters, digits and hyphens only — no underscore (it is the namespace/tool-name separator).
	Name string `json:"name"`

	// OauthClientId OAuth client id for the client_credentials grant (not secret).
	OauthClientId *string `json:"oauth_client_id,omitempty"`

	// OauthClientSecret OAuth client secret as a ${env:VAR} or ${file:path} reference, resolved at connect time. Raw secrets are rejected so the registry never stores one.
	OauthClientSecret *string `json:"oauth_client_secret,omitempty"`

	// OauthScopes OAuth scopes to request; empty = server/registration default.
	OauthScopes *[]string `json:"oauth_scopes,omitempty"`

	// OauthTokenUrl Token endpoint for the client_credentials grant.
	OauthTokenUrl *string `json:"oauth_token_url,omitempty"`

	// StaticHeaders Headers always sent upstream; merged under hook-provided headers. Values may embed ${env:VAR} / ${file:path} secret references resolved at connect time — use those for credentials (e.g. 'Bearer ${env:API_TOKEN}'), because this field is stored in plaintext and returned by the admin read API.
	StaticHeaders  *map[string]string `json:"static_headers,omitempty"`
	Tags           *[]string          `json:"tags,omitempty"`
	TimeoutSeconds *float32           `json:"timeout_seconds,omitempty"`

	// Transport Transport used to reach an upstream MCP server. The gateway proxies remote
	// servers only - local stdio subprocesses are out of scope.
	Transport *Transport `json:"transport,omitempty"`

	// Url Endpoint URL for the upstream MCP server.
	Url string `json:"url"`
}

