// WorkerInstanceInfo One live (or recently-seen) worker replica of a logical agent.
//
// “busy“ means the worker currently owns a run in “claimed“ or “running“ (the queue branch
// enforces at most one active run per worker). “is_online“ reflects heartbeat freshness. A
// “free“ instance (in the aggregate counts on :class:`AgentInstanceResponse`) is one that is
// online but not busy.
type WorkerInstanceInfo struct {
	Busy                *bool      `json:"busy,omitempty"`
	ChannelSeenAt       *string    `json:"channel_seen_at,omitempty"`
	ClusterName         *string    `json:"cluster_name,omitempty"`
	CurrentRunId        *string    `json:"current_run_id,omitempty"`
	CurrentRunStartedAt *string    `json:"current_run_started_at,omitempty"`
	CurrentRunStatus    *RunStatus `json:"current_run_status,omitempty"`
	EndpointUrl         *string    `json:"endpoint_url,omitempty"`
	Generation          *int       `json:"generation,omitempty"`
	IsOnline            *bool      `json:"is_online,omitempty"`
	LastHeartbeatAt     string     `json:"last_heartbeat_at"`
	Namespace           *string    `json:"namespace,omitempty"`
	PodName             *string    `json:"pod_name,omitempty"`
	SdkVersion          *string    `json:"sdk_version,omitempty"`
	SourceCommit        *string    `json:"source_commit,omitempty"`
	SourceDirty         *bool      `json:"source_dirty,omitempty"`
	Version             *string    `json:"version,omitempty"`
	WorkerId            string     `json:"worker_id"`
}

